\subsection*{Appendix A}

\begin{flalign*}
K_{\{\tau, t_x, x_t\}}^{(t, x)} =
\begin{pmatrix}
\tau\\ t_x\\ x_t
\end{pmatrix}_{\!\!K\!\!} =
R_{\tau t_x}^{(+\alpha_x)} k_{\{t, x\}}^{(v)} =
R_{\tau t_x}^{(+\alpha_x)}
\begin{pmatrix}
t\\ A\\ x
\end{pmatrix}_{\!\!k\!\!}  =
\begin{pmatrix}
\begin{array}{r@{}lr@{}lr@{}l}
&\cos\alpha_x & &\sin\alpha_x & &0\\
-&\sin\alpha_x & &\cos\alpha_x & &0\\
&0 & \phantom{+}&0 & &1\\
\end{array}
\end{pmatrix}
\begin{pmatrix}
t\\ A\\ x
\end{pmatrix}_{\!\!k\!\!}  =
\begin{pmatrix}
\begin{array}{r@{}l}
&t\cos\alpha_x + A\sin\alpha_x\\
&A\cos\alpha_x - t\sin\alpha_x\\
&x\\
\end{array}
\end{pmatrix}_{\!\!K\!\!} &&
\end{flalign*}

\begin{flalign*}
{K'}_{\{\tau', t_x', x_t'\}}^{(t', x')} =
\begin{pmatrix}
\tau'\\ t_x'\\ x_t'
\end{pmatrix}_{\!\!K'\!\!} =
R_{\tau t_x}^{(-\alpha_x)} {k'}_{\{t', x'\}}^{(v')} =
R_{\tau t_x}^{(-\alpha_x)}
\begin{pmatrix}
t'\\ A'\\ x'
\end{pmatrix}_{\!\!k'\!\!} =
\begin{pmatrix}
\begin{array}{r@{}lr@{}lr@{}l}
&\cos\alpha_x & -&\sin\alpha_x & &0\\
&\sin\alpha_x & &\cos\alpha_x & &0\\
&0 & \phantom{+}&0 & &1\\
\end{array}
\end{pmatrix}
\begin{pmatrix}
t'\\ A'\\ x'
\end{pmatrix}_{\!\!k'\!\!} =
\begin{pmatrix}
\begin{array}{r@{}l}
&t'\cos\alpha_x - A'\sin\alpha_x\\
&A'\cos\alpha_x + t'\sin\alpha_x\\
&x'\\
\end{array}
\end{pmatrix}_{\!\!K'\!\!}&&
\end{flalign*}

\begin{flalign*}
{K^*}_{\{\tau', t_x', x_t'\}}^{(t, x)}
\begin{pmatrix}
\tau'\\ t_x'\\ x_t'
\end{pmatrix}_{\!\!K^*\!\!} &=
R_{\tau t_x}^{(-2\alpha_x)} K_{\{\tau, t_x, x\}}^{(t,x)} =
R_{\tau t_x}^{(-2\alpha_x)}
\begin{pmatrix}
\tau\\ t_x\\ x_t
\end{pmatrix}_{\!\!K\!\!}&&\\
&= \begin{pmatrix}
\begin{array}{r@{}lr@{}lr@{}l}
&\cos2\alpha_x & -&\sin2\alpha_x & &0\\
+&\sin2\alpha_x & &\cos2\alpha_x & &0\\
&0 & \phantom{+}&0 & &1\\
\end{array}
\end{pmatrix}
\begin{pmatrix}
\tau\\ t_x\\ x_t
\end{pmatrix}_{\!\!K\!\!} =
\begin{pmatrix}
\begin{array}{r@{}l}
&\tau\cos2\alpha_x - t_x\sin2\alpha_x\\
&t_x\cos2\alpha_x - \tau\sin2\alpha_x\\
&x_t\\
\end{array}
\end{pmatrix}_{\!\!K^*\!\!}&&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&t(\cos2\alpha_x\cos\alpha_x + \sin2\alpha_x\sin\alpha_x) + A(\cos2\alpha_x\sin\alpha_x - \sin2\alpha_x\cos\alpha_x)\\
&A(\cos2\alpha_x\cos\alpha_x + \sin2\alpha_x\sin\alpha_x) - t(\cos2\alpha_x\sin\alpha_x - \sin2\alpha_x\cos\alpha_x)\\
&x\\
\end{array}
\end{pmatrix}_{\!\!K^*\!\!}&&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&t\cos\alpha_x - A\sin\alpha_x\\
&A\cos\alpha_x + t\sin\alpha_x\\
&x\\
\end{array}
\end{pmatrix}_{\!\!K^*\!\!}&&
\end{flalign*}

\begin{flalign*}
{{K'}^*}_{\{\tau, t_x, x_t\}}^{(t', x')}
\begin{pmatrix}
\tau\\ t_x\\ x_t
\end{pmatrix}_{\!\!{K'}^*\!\!} &=
R_{\tau t_x}^{(+2\alpha_x)} {K'}_{\{\tau', t_x', x'\}}^{(t',x')} =
R_{\tau t_x}^{(-2\alpha_x)}
\begin{pmatrix}
\tau'\\ t_x'\\ x_t'
\end{pmatrix}_{\!\!{K'}\!\!} &&\\
&= \begin{pmatrix}
\begin{array}{r@{}lr@{}lr@{}l}
&\cos2\alpha_x & +&\sin2\alpha_x & &0\\
-&\sin2\alpha_x & &\cos2\alpha_x & &0\\
&0 & \phantom{+}&0 & &1\\
\end{array}
\end{pmatrix}
\begin{pmatrix}
\tau'\\ t_x'\\ x_t'
\end{pmatrix}_{\!\!K'\!\!}=
\begin{pmatrix}
\begin{array}{r@{}l}
&\tau'\cos2\alpha_x - t_x'\sin2\alpha_x\\
&t_x'\cos2\alpha_x - \tau'\sin2\alpha_x\\
&x_t'\\
\end{array}
\end{pmatrix}_{\!\!{K'}^*\!\!}&&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&t'(\cos2\alpha_x\cos\alpha_x + \sin2\alpha_x\sin\alpha_x) - A'(\cos2\alpha_x\sin\alpha_x - \sin2\alpha_x\cos\alpha_x)\\
&A'(\cos2\alpha_x\cos\alpha_x + \sin2\alpha_x\sin\alpha_x) + t'(\cos2\alpha_x\sin\alpha_x - \sin2\alpha_x\cos\alpha_x)\\
&x\\
\end{array}
\end{pmatrix}_{\!\!{K'}^*\!\!}&&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&t'\cos\alpha_x +A'\sin\alpha_x\\
&A'\cos\alpha_x - t'\sin\alpha_x\\
&x\\
\end{array}
\end{pmatrix}_{\!\!{K'}^*\!\!}&&
\end{flalign*}

\clearpage
\begin{flalign*}
{k'}_{\{t', x'\}}^{(v)} =
\begin{pmatrix}
t'\\ x'
\end{pmatrix}_{\!\!k'\!\!} &=
\begin{pmatrix}
\begin{array}{r@{}lr@{}lr@{}l}
&1 & &\lambda & \frac{1}{c}&\lambda\\
&1 & &\lambda & c&\lambda\\
\end{array}
\end{pmatrix}
\begin{pmatrix}
\begin{array}{r@{}l}
&t\cos\alpha_x - A\sin\alpha_x\\
&A\cos\alpha_x + t\sin\alpha_x\\
&x\\
\end{array}
\end{pmatrix}_{\!\!K^*\!\!} &&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&t\cos\alpha_x - A\sin\alpha_x + A\lambda\cos\alpha_x +t\lambda\sin\alpha_x + \frac{1}{c}\lambda x\\
&t\cos\alpha_x - A\sin\alpha_x + A\lambda\cos\alpha_x +t\lambda\sin\alpha_x + c\lambda x\\
\end{array}
\end{pmatrix}_{\!\!k'\!\!} &&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&t\frac{1}{\gamma} - A\beta + A\frac{\lambda}{\gamma} + t\lambda\beta + \frac{1}{c}\lambda x\\
&t\frac{1}{\gamma} - A\beta + A\frac{\lambda}{\gamma} + t\lambda\beta + c\lambda x\\
\end{array}
\end{pmatrix}_{\!\!k'\!\!} \quad\quad \cos\alpha_x=\frac{1}{\gamma} \,\,;\,\, \sin\alpha_x\quad\quad&&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&\gamma(t + \frac{vx}{c^2})\\
&\gamma(t + vx)\\
\end{array}
\end{pmatrix}_{\!\!k'(v)\!\!} \quad\quad \lambda=\beta\gamma=-\beta'\gamma'&&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&\gamma(t - \frac{vx}{c^2})\\
&\gamma(t - vx)\\
\end{array}
\end{pmatrix}_{\!\!k'(v')\!\!}&&
\end{flalign*}

\begin{flalign*}
{k}_{\{t, x\}}^{(v)} =
\begin{pmatrix}
t\\ x
\end{pmatrix}_{\!\!k\!\!} &=
\begin{pmatrix}
\begin{array}{r@{}lr@{}lr@{}l}
&1 & &\lambda & \frac{1}{c}&\lambda\\
&1 & &\lambda & c&\lambda\\
\end{array}
\end{pmatrix}
\begin{pmatrix}
\begin{array}{r@{}l}
&t'\cos\alpha_x + A'\sin\alpha_x\\
&A'\cos\alpha_x - t'\sin\alpha_x\\
&x'\\
\end{array}
\end{pmatrix}_{\!\!{K'}^*\!\!} &&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&t'\cos\alpha_x + A'\sin\alpha_x + A'\lambda\cos\alpha_x - t\lambda\sin\alpha_x + \frac{1}{c}\lambda x\\
&t'\cos\alpha_x + A'\sin\alpha_x + A'\lambda\cos\alpha_x - t\lambda\sin\alpha_x + c\lambda x\\
\end{array}
\end{pmatrix}_{\!\!k\!\!} &&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&t\frac{1}{\gamma} + A\beta + A\frac{\lambda}{\gamma} - t\lambda\beta + \frac{1}{c}\lambda x\\
&t\frac{1}{\gamma} + A\beta + A\frac{\lambda}{\gamma} - t\lambda\beta + c\lambda x\\
\end{array}
\end{pmatrix}_{\!\!k\!\!} \quad\quad \cos\alpha_x=\frac{1}{\gamma} \,\,;\,\, \sin\alpha_x\quad\quad&&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&\gamma(t - \frac{vx}{c^2})\\
&\gamma(t - vx)\\
\end{array}
\end{pmatrix}_{\!\!k(v)\!\!} \quad\quad \lambda=-\beta\gamma=\beta'\gamma'&&\\
&= \begin{pmatrix}
\begin{array}{r@{}l}
&\gamma(t + \frac{vx}{c^2})\\
&\gamma(t + vx)\\
\end{array}
\end{pmatrix}_{\!\!k(v')\!\!}&&
\end{flalign*}

